import{_ as e,o as a,c as i,ag as r}from"./chunks/framework.6MCaaFDc.js";const u=JSON.parse('{"title":"Privacy & Ethics","description":"","frontmatter":{},"headers":[],"relativePath":"theory/social/privacy-ethics.md","filePath":"theory/social/privacy-ethics.md"}'),o={name:"theory/social/privacy-ethics.md"};function n(s,t,d,l,c,h){return a(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="privacy-ethics" tabindex="-1">Privacy &amp; Ethics <a class="header-anchor" href="#privacy-ethics" aria-label="Permalink to &quot;Privacy &amp; Ethics&quot;">​</a></h1><p>The digital world has created unprecedented challenges for privacy. Every app you install, every website you visit, and every post you make leaves data about you in the hands of others. Understanding privacy rights, ethical responsibilities, and the legal framework is essential for every digital citizen.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 11–12</p><p>Privacy, ethics, and social networking effects are Grade 11 content. POPIA, surveillance, and AI ethics are extended at Grade 12.</p></div><hr><h2 id="what-is-privacy" tabindex="-1">What is Privacy? <a class="header-anchor" href="#what-is-privacy" aria-label="Permalink to &quot;What is Privacy?&quot;">​</a></h2><p><strong>Privacy</strong> is the right of individuals to control how their personal information is collected, stored, used, and shared.</p><p><strong>Personal information includes:</strong></p><ul><li>Full name, address, phone number, email</li><li>ID number, passport number</li><li>Financial information (bank account, credit card)</li><li>Health and medical records</li><li>Location data</li><li>Biometric data (fingerprints, face scan)</li><li>Online behaviour (browsing history, purchases)</li><li>Opinions, beliefs, political affiliation</li></ul><p><strong>The privacy paradox:</strong> People say they value privacy, but voluntarily share enormous amounts of personal data on social media and with apps.</p><hr><h2 id="why-privacy-matters" tabindex="-1">Why Privacy Matters <a class="header-anchor" href="#why-privacy-matters" aria-label="Permalink to &quot;Why Privacy Matters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Reason</th><th>Explanation</th></tr></thead><tbody><tr><td><strong>Protection from harm</strong></td><td>Identity theft, fraud, and targeted harassment require personal data</td></tr><tr><td><strong>Autonomy</strong></td><td>Control over your own narrative and how others see you</td></tr><tr><td><strong>Trust</strong></td><td>Confidence that organisations handle data responsibly</td></tr><tr><td><strong>Freedom of expression</strong></td><td>People self-censor when they know they&#39;re being monitored</td></tr><tr><td><strong>Political freedom</strong></td><td>Surveillance chills dissent and political activity</td></tr></tbody></table><hr><h2 id="how-personal-data-is-collected" tabindex="-1">How Personal Data is Collected <a class="header-anchor" href="#how-personal-data-is-collected" aria-label="Permalink to &quot;How Personal Data is Collected&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Source</th><th>How</th><th>Examples</th></tr></thead><tbody><tr><td><strong>Social media</strong></td><td>User input + behavioural tracking</td><td>Posts, likes, location check-ins</td></tr><tr><td><strong>Search engines</strong></td><td>Search history, click patterns</td><td>Google search history</td></tr><tr><td><strong>Apps</strong></td><td>Location, contacts, microphone, camera</td><td>Weather app tracking location</td></tr><tr><td><strong>Cookies</strong></td><td>Browser tracking across sites</td><td>Advertising cookies</td></tr><tr><td><strong>IoT devices</strong></td><td>Sensor data from smart home devices</td><td>Alexa recording conversations</td></tr><tr><td><strong>Loyalty programs</strong></td><td>Purchase history</td><td>Pick n Pay Smart Shopper</td></tr><tr><td><strong>CCTV</strong></td><td>Facial recognition from cameras</td><td>Public surveillance cameras</td></tr><tr><td><strong>Data brokers</strong></td><td>Aggregating from many sources</td><td>Selling profile data to advertisers</td></tr></tbody></table><hr><h2 id="ethics-in-ict" tabindex="-1">Ethics in ICT <a class="header-anchor" href="#ethics-in-ict" aria-label="Permalink to &quot;Ethics in ICT&quot;">​</a></h2><p><strong>Ethics</strong> in ICT involves making morally responsible decisions about technology.</p><h3 id="key-ethical-principles" tabindex="-1">Key Ethical Principles <a class="header-anchor" href="#key-ethical-principles" aria-label="Permalink to &quot;Key Ethical Principles&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Principle</th><th>Description</th></tr></thead><tbody><tr><td><strong>Informed consent</strong></td><td>Users should know what data is collected and agree to it</td></tr><tr><td><strong>Data minimisation</strong></td><td>Collect only data that is necessary</td></tr><tr><td><strong>Transparency</strong></td><td>Be open about how data is used</td></tr><tr><td><strong>Fairness</strong></td><td>Don&#39;t discriminate; don&#39;t use data to harm people</td></tr><tr><td><strong>Accountability</strong></td><td>Organisations responsible for breaches and misuse</td></tr><tr><td><strong>Purpose limitation</strong></td><td>Use data only for the stated purpose</td></tr></tbody></table><h3 id="ethical-issues-in-ict" tabindex="-1">Ethical Issues in ICT <a class="header-anchor" href="#ethical-issues-in-ict" aria-label="Permalink to &quot;Ethical Issues in ICT&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Issue</th><th>Ethical concern</th></tr></thead><tbody><tr><td><strong>Surveillance capitalism</strong></td><td>Businesses profiting by collecting and selling personal data</td></tr><tr><td><strong>Algorithmic bias</strong></td><td>AI systems that discriminate based on race, gender, age</td></tr><tr><td><strong>Deepfakes</strong></td><td>AI-generated fake videos/images that deceive</td></tr><tr><td><strong>AI decision-making</strong></td><td>Who is responsible when an AI makes a harmful decision?</td></tr><tr><td><strong>Digital manipulation</strong></td><td>Social media algorithms designed to maximise engagement (outrage)</td></tr><tr><td><strong>Facial recognition</strong></td><td>Surveillance without consent in public spaces</td></tr><tr><td><strong>Data retention</strong></td><td>How long should organisations keep personal data?</td></tr></tbody></table><hr><h2 id="social-networking-and-its-effects" tabindex="-1">Social Networking and Its Effects <a class="header-anchor" href="#social-networking-and-its-effects" aria-label="Permalink to &quot;Social Networking and Its Effects&quot;">​</a></h2><h3 id="positive-effects" tabindex="-1">Positive Effects <a class="header-anchor" href="#positive-effects" aria-label="Permalink to &quot;Positive Effects&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Effect</th><th>Explanation</th></tr></thead><tbody><tr><td><strong>Communication</strong></td><td>Instant, free communication with anyone globally</td></tr><tr><td><strong>Community</strong></td><td>Finding others with shared interests</td></tr><tr><td><strong>Activism</strong></td><td>Organising social movements, awareness campaigns</td></tr><tr><td><strong>Education</strong></td><td>Sharing knowledge and learning resources</td></tr><tr><td><strong>Business</strong></td><td>Marketing, networking, customer engagement</td></tr><tr><td><strong>News</strong></td><td>Real-time information sharing</td></tr></tbody></table><h3 id="negative-effects" tabindex="-1">Negative Effects <a class="header-anchor" href="#negative-effects" aria-label="Permalink to &quot;Negative Effects&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Effect</th><th>Explanation</th></tr></thead><tbody><tr><td><strong>Privacy erosion</strong></td><td>Vast personal data harvested and sold</td></tr><tr><td><strong>Misinformation</strong></td><td>Fake news spreads faster than corrections</td></tr><tr><td><strong>Echo chambers</strong></td><td>Algorithms show content you agree with → reinforces existing views</td></tr><tr><td><strong>Cyberbullying</strong></td><td>Harassment at scale, 24/7</td></tr><tr><td><strong>Addiction</strong></td><td>Variable reward mechanisms keep users engaged (like gambling)</td></tr><tr><td><strong>Social comparison</strong></td><td>Highlight reels → unrealistic standards → anxiety, depression</td></tr><tr><td><strong>Radicalisation</strong></td><td>Extremist content recommendations</td></tr><tr><td><strong>Time theft</strong></td><td>Excessive screen time reduces productivity</td></tr></tbody></table><hr><h2 id="south-african-privacy-law-—-popia" tabindex="-1">South African Privacy Law — POPIA <a class="header-anchor" href="#south-african-privacy-law-—-popia" aria-label="Permalink to &quot;South African Privacy Law — POPIA&quot;">​</a></h2><p><strong>POPIA</strong> (Protection of Personal Information Act, 2013, effective 2021) is South Africa&#39;s data protection law.</p><h3 id="what-popia-covers" tabindex="-1">What POPIA covers: <a class="header-anchor" href="#what-popia-covers" aria-label="Permalink to &quot;What POPIA covers:&quot;">​</a></h3><ul><li>Any organisation or individual processing personal information of South Africans</li><li>&quot;Processing&quot; includes collecting, storing, using, sharing, deleting data</li></ul><h3 id="_8-conditions-for-lawful-processing" tabindex="-1">8 Conditions for Lawful Processing <a class="header-anchor" href="#_8-conditions-for-lawful-processing" aria-label="Permalink to &quot;8 Conditions for Lawful Processing&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Condition</th><th>Requirement</th></tr></thead><tbody><tr><td><strong>Accountability</strong></td><td>Responsible party must ensure compliance</td></tr><tr><td><strong>Processing limitation</strong></td><td>Only process with consent or legitimate reason</td></tr><tr><td><strong>Purpose specification</strong></td><td>State purpose before collecting; use only for that purpose</td></tr><tr><td><strong>Further processing limitation</strong></td><td>Don&#39;t use data for incompatible purposes</td></tr><tr><td><strong>Information quality</strong></td><td>Data must be complete, accurate, and up to date</td></tr><tr><td><strong>Openness</strong></td><td>Notify data subject of collection; publish privacy policy</td></tr><tr><td><strong>Security safeguards</strong></td><td>Protect data from loss, damage, unauthorised access</td></tr><tr><td><strong>Data subject participation</strong></td><td>Individuals can access and correct their own data</td></tr></tbody></table><h3 id="rights-under-popia" tabindex="-1">Rights under POPIA: <a class="header-anchor" href="#rights-under-popia" aria-label="Permalink to &quot;Rights under POPIA:&quot;">​</a></h3><ul><li>Right to know what data is held about you</li><li>Right to access your personal data</li><li>Right to correct inaccurate data</li><li>Right to object to processing</li><li>Right to request deletion (&quot;right to be forgotten&quot;)</li></ul><h3 id="popia-penalties" tabindex="-1">POPIA penalties: <a class="header-anchor" href="#popia-penalties" aria-label="Permalink to &quot;POPIA penalties:&quot;">​</a></h3><ul><li>Fines up to <strong>R10 million</strong></li><li>Imprisonment up to <strong>10 years</strong> for serious offences</li><li>Regulatory body: <strong>Information Regulator</strong></li></ul><hr><h2 id="gdpr-european-equivalent" tabindex="-1">GDPR (European equivalent) <a class="header-anchor" href="#gdpr-european-equivalent" aria-label="Permalink to &quot;GDPR (European equivalent)&quot;">​</a></h2><p><strong>GDPR</strong> (General Data Protection Regulation, 2018) is the EU equivalent of POPIA.</p><table tabindex="0"><thead><tr><th>Feature</th><th>GDPR</th></tr></thead><tbody><tr><td>Coverage</td><td>Any organisation handling EU residents&#39; data</td></tr><tr><td>Max fine</td><td>€20 million or 4% of global annual turnover</td></tr><tr><td>Consent</td><td>Must be freely given, specific, informed, unambiguous</td></tr><tr><td>Right to deletion</td><td>&quot;Right to be forgotten&quot;</td></tr></tbody></table><p>GDPR set the global standard — POPIA is modelled on it.</p><hr><h2 id="digital-rights-and-responsibilities" tabindex="-1">Digital Rights and Responsibilities <a class="header-anchor" href="#digital-rights-and-responsibilities" aria-label="Permalink to &quot;Digital Rights and Responsibilities&quot;">​</a></h2><h3 id="rights" tabindex="-1">Rights <a class="header-anchor" href="#rights" aria-label="Permalink to &quot;Rights&quot;">​</a></h3><ul><li>Right to access information</li><li>Right to privacy</li><li>Right to be forgotten (deletion of personal data)</li><li>Right to know how your data is used</li><li>Freedom from surveillance and discrimination</li></ul><h3 id="responsibilities" tabindex="-1">Responsibilities <a class="header-anchor" href="#responsibilities" aria-label="Permalink to &quot;Responsibilities&quot;">​</a></h3><ul><li>Respect others&#39; privacy — don&#39;t share private information</li><li>Think before posting — impact on others&#39; dignity</li><li>Report illegal content (child exploitation, hate speech)</li><li>Verify information before sharing (stop misinformation)</li><li>Respect intellectual property (no piracy)</li><li>Use technology ethically</li></ul><hr><h2 id="artificial-intelligence-—-ethical-considerations" tabindex="-1">Artificial Intelligence — Ethical Considerations <a class="header-anchor" href="#artificial-intelligence-—-ethical-considerations" aria-label="Permalink to &quot;Artificial Intelligence — Ethical Considerations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Issue</th><th>Detail</th></tr></thead><tbody><tr><td><strong>Bias</strong></td><td>AI trained on biased data produces biased outputs — e.g. facial recognition performs worse on darker skin tones</td></tr><tr><td><strong>Accountability</strong></td><td>Who is responsible when AI makes a wrong decision (self-driving car accident)?</td></tr><tr><td><strong>Transparency</strong></td><td>&quot;Black box&quot; AI — decisions cannot be explained</td></tr><tr><td><strong>Job displacement</strong></td><td>Automation replacing human workers</td></tr><tr><td><strong>Privacy</strong></td><td>AI systems require massive data collection</td></tr><tr><td><strong>Deepfakes</strong></td><td>Convincing fake media threatens truth and trust</td></tr><tr><td><strong>Weaponisation</strong></td><td>AI in autonomous weapons systems</td></tr></tbody></table><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Privacy</strong></td><td>Right to control how personal information is collected and used</td></tr><tr><td><strong>Personal information</strong></td><td>Any data that identifies or can identify a person</td></tr><tr><td><strong>POPIA</strong></td><td>South African Protection of Personal Information Act (2013)</td></tr><tr><td><strong>GDPR</strong></td><td>EU General Data Protection Regulation (2018)</td></tr><tr><td><strong>Informed consent</strong></td><td>Agreement based on full understanding of what is being agreed to</td></tr><tr><td><strong>Data minimisation</strong></td><td>Collecting only data that is necessary</td></tr><tr><td><strong>Digital footprint</strong></td><td>Trail of data left by online activity</td></tr><tr><td><strong>Algorithmic bias</strong></td><td>AI producing unfair results due to biased training data</td></tr><tr><td><strong>Echo chamber</strong></td><td>Online environment exposing people only to opinions they already hold</td></tr><tr><td><strong>Surveillance capitalism</strong></td><td>Business model based on collecting and selling personal data</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;What is POPIA? What does it aim to protect?&quot;</strong> — Protection of Personal Information Act; aims to protect individuals&#39; personal information from misuse by organisations; sets conditions for lawful processing</p></li><li><p><strong>&quot;Give TWO rights that POPIA grants to individuals&quot;</strong> — right to access own data; right to correct inaccurate data; right to object to processing; right to request deletion</p></li><li><p><strong>&quot;Give TWO negative effects of social media on society&quot;</strong> — spread of misinformation; cyberbullying; echo chambers reinforce existing views; addiction by design; privacy erosion; social comparison causing anxiety</p></li><li><p><strong>&quot;What is algorithmic bias? Give an example.&quot;</strong> — AI systems that produce unfair outcomes due to biased training data; example: facial recognition that works less accurately on darker skin tones</p></li><li><p><strong>&quot;Explain the concept of informed consent in the context of data collection&quot;</strong> — Users must know specifically what data is collected, how it will be used, and who it will be shared with, and must actively agree to this before data is collected</p></li></ol></div>',59)])])}const p=e(o,[["render",n]]);export{u as __pageData,p as default};
